import styled from '@emotion/styled';
import { colors } from 'core';

import { Props } from './props';

export const Header = styled.button<Props>`
  width: 100%;
  text-align: left;
  &:not:first-child {
    border-bottom: 2px solid ${colors.variants.Neutral.LightGrey};
  }
`;
